class Solution:
    def largestMerge(self, word1, word2):
        i, j = 0, 0
        n, m = len(word1), len(word2)
        out = []
        while i < n and j < m:
            if word1[i] > word2[j]:
                out.append(word1[i]); i += 1
            elif word1[i] < word2[j]:
                out.append(word2[j]); j += 1
            elif word1[i:] >= word2[j:]:
                out.append(word1[i]); i += 1
            else:
                out.append(word2[j]); j += 1
        out.append(word1[i:])
        out.append(word2[j:])
        return ''.join(out)

