var largestMerge = function(word1, word2) {
    let i = 0, j = 0;
    const n = word1.length, m = word2.length;
    const out = [];
    while (i < n && j < m) {
        if (word1[i] > word2[j]) { out.push(word1[i]); i++; }
        else if (word1[i] < word2[j]) { out.push(word2[j]); j++; }
        else if (word1.slice(i) >= word2.slice(j)) { out.push(word1[i]); i++; }
        else { out.push(word2[j]); j++; }
    }
    out.push(word1.slice(i));
    out.push(word2.slice(j));
    return out.join('');
};
